import React from 'react';
import './Hero.css';
import Button from 'react-bootstrap/Button';
import Image from 'react-bootstrap/Image';

const Hero = () => {
  return (
    <div className='hero text-center p-5'>
      <h1>Best Collection of Products</h1>
      <p>Lorem ipsum dolor sit amet, consectetur adipisicing elit. Sed reprehenderit facere magnam...</p>
      <Button variant="primary" className="my-3">Shop Now</Button>
      <Image src="../Assets/hero_image.png/171x180" rounded />
    </div>
  )
}

export default Hero;
